changeSet.sql:
DO $$
DECLARE
    /* each entry: which roles get which granular perms in place of old :write */
    grants jsonb := '[
      {"role": "TENANT_ADMIN",   "perms": ["customer:delete","supplier:create","supplier:update","supplier:delete","sales:create","sales:update","expense:update","expense:delete","payment:update","delivery:create","delivery:update","purchase:create","purchase:update","lot:create","lot:update","lot:delete"]},
      {"role": "MANAGER",        "perms": ["customer:delete","supplier:create","supplier:update","supplier:delete","sales:create","sales:update","expense:update","expense:delete","payment:update","delivery:create","delivery:update","purchase:create","purchase:update","lot:create","lot:update","lot:delete"]},
      {"role": "ACCOUNTANT",     "perms": ["supplier:create","supplier:update","supplier:delete","purchase:create","purchase:update"]},
      {"role": "PAYMENT_OFFICER","perms": ["customer:delete","supplier:create","supplier:update","supplier:delete","payment:update","purchase:create","purchase:update"]},
      {"role": "CASHIER",        "perms": ["customer:delete","sales:create","sales:update","payment:update"]},
      {"role": "STOCK_KEEPER",   "perms": ["delivery:create","delivery:update","lot:create","lot:update","lot:delete"]}
    ]'::jsonb;
    entry jsonb;
    rcode text;
    pcodes text[];
BEGIN
    FOR entry IN SELECT * FROM jsonb_array_elements(grants) LOOP
        rcode := entry->>'role';
        SELECT ARRAY(SELECT jsonb_array_elements_text(entry->'perms')) INTO pcodes;
        INSERT INTO role_permission (role_id, permission_id)
        SELECT r.id, p.id
        FROM roles r
        JOIN permissions p ON p.code = ANY(pcodes)
        WHERE r.code = rcode
        ON CONFLICT DO NOTHING;
    END LOOP;
END $$;

/* CASCADE on role_permission.permission_id removes the role grants */
DELETE FROM permissions WHERE code IN (
    'customer:write','supplier:write','sales:write','expense:write',
    'payment:write','delivery:write','purchase:write','lot:write',
    'sale:create','sale:read'
);
